steps.command:
SELECT column_name, data_type, column_default 
FROM information_schema.columns 
WHERE table_schema = 'bookings' AND table_name = 'flights' AND column_name = 'flight_id';

SELECT pid, state, wait_event_type, wait_event, query, backend_start, query_start, state_change 
FROM pg_stat_activity 
WHERE wait_event_type = 'Lock' OR state = 'active';

SELECT relname, n_live_tup, n_dead_tup, last_vacuum, last_autovacuum, last_analyze, last_autoanalyze 
FROM pg_stat_all_tables 
WHERE schemaname = 'bookings' AND relname = 'bookings';

SELECT pid, now() - xact_start AS duration, query, state 
FROM pg_stat_activity 
WHERE state != 'idle' AND (now() - xact_start) > interval '5 minutes';

SELECT pg_size_pretty(pg_total_relation_size('bookings.bookings')) AS total_size, 
       pg_size_pretty(pg_relation_size('bookings.bookings')) AS table_size, 
       pg_size_pretty(pg_indexes_size('bookings.bookings')) AS index_size;

SELECT pid, state, now() - xact_start AS duration, query 
FROM pg_stat_activity 
WHERE state = 'idle in transaction';

SELECT name, setting 
FROM pg_settings 
WHERE name LIKE 'autovacuum%';

SELECT relname, n_live_tup, n_dead_tup 
FROM pg_stat_all_tables 
WHERE schemaname = 'bookings' AND relname = 'bookings';

SELECT relname, last_analyze, last_autoanalyze, n_live_tup, n_dead_tup 
FROM pg_stat_user_tables 
WHERE relname IN ('flights', 'ticket_flights');

SELECT relname, last_analyze, last_autoanalyze, n_live_tup, n_dead_tup 
FROM pg_stat_user_tables 
WHERE relname IN ('flights', 'ticket_flights');

SELECT relname, n_live_tup, n_dead_tup, last_vacuum, last_autovacuum, last_analyze, last_autoanalyze 
FROM pg_stat_all_tables 
WHERE schemaname = 'bookings';
